    public Object deserializeObject(byte[] serializedData) throws IOException, ClassNotFoundException {
        // Validate input
        if (serializedData == null || serializedData.length == 0) {
            throw new IllegalArgumentException("Serialized data cannot be null or empty");
        }

        try (ByteArrayInputStream bais = new ByteArrayInputStream(serializedData);
             SecureObjectInputStream ois = new SecureObjectInputStream(bais)) {

            return ois.readObject();
        }
    }

    /**
     * Secure ObjectInputStream that restricts which classes can be deserialized.
     */
    private static class SecureObjectInputStream extends ObjectInputStream {

        public SecureObjectInputStream(InputStream in) throws IOException {
            super(in);
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {

            String className = desc.getName();

            // Check if the class is in our allowed list
            if (!ALLOWED_CLASSES.contains(className)) {
                // Check for primitive array types
                if (className.startsWith("[L") && className.endsWith(";")) {
                    String elementClass = className.substring(2, className.length() - 1);
                    if (ALLOWED_CLASSES.contains(elementClass)) {
                        return super.resolveClass(desc);
                    }
                }

                throw new ClassNotFoundException("Unauthorized deserialization attempt: " + className);
            }

            return super.resolveClass(desc);
        }
    }
}
